INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146029', 'AetherGen-masks', 'This compound was sent by Jun Qi from DFCI   Hi, Kris,    Here is the tracking number for the shipment.  777391828604   Let me know if you have any question.   Thanks  jun     Jun Qi, Ph.D.   Assistant Professor of Medicine, Department of Cancer Biology Dana-Farber Cancer Institute Harvard Medical School 360 Longwood Ave. LC-2210 Boston, MA 02115 617-632-6629  617-582-8290 jun_qi@dfci.harvard.edu   [AetherGen LIMS Verified]', '{"BOOK": "9", "ISID": "s.chen2", "PAGE": "2", "DESCR": "EZ53", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138788", "MODIFIED_DATE": "09/11/2016", "COMPLETED_DATE": "01/11/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138788", "COUNTERSIGNED_DATE": "09/11/2016"}', '2025-01-30');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146049', 'AetherGen-masks', 'To 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 6-Chloropyridine-2,3-diamine (110.0 mg, 0.77 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction was diluted with water, extracted with ethyl acetate, the EtOAc layer was washed with water, brine, dried over sodium sulfate, filterred and concentrated. The crude was triturated with DCM, and the solid obtained was filtered. The solid was washed with ethyl acetate, DCM  to give 2-(4-benzyloxyphenyl)-5-chloro-3H-imidazo[4,5-b]pyridine (68 mg, 0.20251 mmol, 26.431% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "13", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138808", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138808", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-01-30');
