INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146045', 'AetherGen-masks', 'REF: Minmin Yang, Wei Ye, and Stewart W. Schneller, J . O r g . C h e m .2004, 6 9 , 3993-3996 To  (6R,6aR)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-ol (780.0 mg, 4.23 mmol){{9:row 1}}_XXXXX_  in 25 mL of anhydrous THF under an atmosphere of nitrogen at 0 oC was  added the triphenylphosphane (2240.0 mg, 8.54 mmol){{9:row 4}}_XXXXX_  and isopropyl (NE)-N-isopropoxycarbonyliminocarbamate (1.55 mL, 7.87 mmol){{9:row 3}}_XXXXX_  dropwise. The reaction mixture was stirred for 30 mins and to this was added the 6-Chloropurine (942.0 mg, 6.09 mmol){{9:row 2}}_XXXXX_ . The reaction mixture was allowed to warm up to room temperature and stirred for 12 h, follwed by heating at 50 oC for additional 8 h. The reaction mixture was concentrated under vacuum and the crude mixture was purified by silica gel chromatography using a 80 g Agela silica gel column and gradient of 0-50% EtOAc in hexane over 40 mins to give (9S)-9-[(3aR,6S)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-yl]-6-chloro-purine (1.2 g, 3.741 mmol, 88.36% yield){{2:row 1}}_XXXXX_  which was contaminated with DIAD byproducts. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "11", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "10/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138804", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138804", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-01-30');
