INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146027', 'AetherGen-prod-sdpo-8251', 'A mixture of (2R,3R,4S,5R)-2-(4-amino-5-iodo-pyrrolo[2,3-d]pyrimidin-7-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (1000.0 mg, 2.55 mmol){{9:row 1}}_XXXXX_ , 2,2-Dimethoxypropane (3.14 mL, 25.5 mmol){{9:row 2}}_XXXXX_ , and 4-methylbenzenesulfonic acid;hydrate (97.01 mg, 0.51 mmol){{9:row 3}}_XXXXX_  in DMF (5 mL){{3:row 1}}_XXXXX_  was heated in a sealed reactor at 80 °C{{8:row 1}}_XXXXX_  overnight. Starting material remained and multiple spots were formed. The reaction was discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "20", "DESCR": "JP-0057", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138786", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "04/12/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138786", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-01-30');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146026', 'AetherGen-masks', 'A mixture of [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (400.0 mg, 0.69 mmol){{9:row 1}}_XXXXX_ , and sodium;iodide (311.8 mg, 2.08 mmol){{9:row 2}}_XXXXX_  in Acetone (5 mL){{3:row 1}}_XXXXX_  was stirred at 60 °C{{8:row 1}}_XXXXX_  overnight. TLC showed no product (should be less polar) but only the polar spot that was likely the hydrolyzed by-product. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "19", "DESCR": "Iodide replacement of Tosylate", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "05/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138785", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "04/12/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138785", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-01-30');
