INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146016', 'AetherGen-masks', 'A mixture of[(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (100.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_ , azetidine-3-carbonitrile hydrochloride (41.11 mg, 0.35 mmol){{9:row 2}}_XXXXX_ , in IPA (1 mL){{3:row 1}}_XXXXX_  was heated at 80 °C{{8:row 1}}_XXXXX_  overnight.   The TLC showed OTs was hydrolyzed back to OH. This reaction can''t use TEA as base as it forms stable ammonium salt. Hunig base would be used for this type of reaction. Discard This target was not pursued further due to azetine analog MD-0041/PRT1000096 was inactive [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "18", "DESCR": "Cyanoazetidine replacement of TsO", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "03/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138775", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138775", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-01-30');
