INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145967', 'AetherGen-masks', 'borane;sodium hydride (11.21 mg, 0.3 mmol){{9:row 2}}_XXXXX_  was added to a suspension of  9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]purin-6-amine (50.0 mg, 0.15 mmol){{9:row 1}}_XXXXX_    in Methanol (1 mL){{3:row 1}}_XXXXX_   at RT. The gas bubbles observed. The reaction mixture remained as suspension. TLC can''t tell if the reaction occurred after an aliquot was treated with Sat. NH4Cl aq., whcih was extracted with EtOAc. NH2 likely need to be protected. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "15", "DESCR": "Reduction of purine with NaBH4---Int-3", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138726", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138726", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-01-30');
