INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145946', 'AetherGen-masks', 'N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_  was added to a mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  and 3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_  in IPA (0.50 mL){{3:row 1}}_XXXXX_  . The resulting mixture was sealed and heated at 88 °C{{8:row 1}}_XXXXX_  over night. TLC showed remaining starting material closed eluted with product (more polar, bright blue on TLC) in 10% MeOH in EtOAc. The reaction mixture was concentrated, loaded on a 20 g silica gel column and purified to give (2R,3R,4S,5R)-2-[6-amino-2-(3-fluoroazetidin-1-yl)purin-9-yl]-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (12 mg, 0.03174 mmol, 19.149% yield){{2:row 1}}_XXXXX_   as white solid. HNMR showed about 10% starting material was contaminated.(2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_    C12H16N4O3SN,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   was added to A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_    88 °C{{8:row 1}}_XXXXX_   IPA (0.50 mL){{3:row 1}}_XXXXX_    [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "8", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138705", "MODIFIED_DATE": "07/10/2016", "COMPLETED_DATE": "04/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138705", "COUNTERSIGNED_DATE": "07/10/2016"}', '2025-01-30');
