INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146085', 'AetherGen-masks', '  Reference: J . O r g . C h e m .2004, 6 9 , 3993-3996 399 To the 9-[(3aS,4R,6R)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-yl]-6-chloro-purine (25.0 mg, 0.08 mmol){{9:row 1}}_XXXXX_  in 1 mL of methanol was added 1mL of 1 M HCl and stirred at room temperature for 2 h. The reaction mixture was concentrated under vacuum and the crude in 1:1methaol water was added the Amberlyst IRA 67 and stirred for 1 h. The mixture was filtered and concentrated. The 1H NMR of crude was not consistent with desired product. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "15", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "19/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138844", "MODIFIED_DATE": "25/03/2017", "COMPLETED_DATE": "16/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138844", "COUNTERSIGNED_DATE": "25/03/2017"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146085', 'AetherGen-prod-sdpo-8251', '  Reference: J . O r g . C h e m .2004, 6 9 , 3993-3996 399 To the 9-[(3aS,4R,6R)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-yl]-6-chloro-purine (25.0 mg, 0.08 mmol){{9:row 1}}_XXXXX_  in 1 mL of methanol was added 1mL of 1 M HCl and stirred at room temperature for 2 h. The reaction mixture was concentrated under vacuum and the crude in 1:1methaol water was added the Amberlyst IRA 67 and stirred for 1 h. The mixture was filtered and concentrated. The 1H NMR of crude was not consistent with desired product. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "15", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "19/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138844", "MODIFIED_DATE": "25/03/2017", "COMPLETED_DATE": "16/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138844", "COUNTERSIGNED_DATE": "25/03/2017"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145866', 'AetherGen-masks', 'To  9-[(3aR,4R,6S,6aS)-6-(iodomethyl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]purin-6-amine (100.0 mg, 0.24 mmol){{9:row 1}}_XXXXX_   in 1 mL of toluene was added  the 2,3,4,6,7,8,9,10-octahydropyrimido[1,2-a]azepine (0.36 mL, 2.4 mmol){{9:row 2}}_XXXXX_  and the reacttion stirred for 2 days. The reaction was discarded. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "3", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "09/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138625", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138625", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146066', 'AetherGen-masks', 'REF: Minmin Yang, Wei Ye, and Stewart W. Schneller, J . O r g . C h e m .2004, 6 9 , 3993-3996 To  COPPER(I) BROMIDE-DIMETHYL SULFID (408.33 mg, 1.99 mmol){{9:row 3}}_XXXXX_  in 80 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (28.3 mL, 28.38 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (3.5 g, 22.7 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (5.76 mL, 45.41 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (10.5 mL, 60.35 mmol){{9:row 4}}_XXXXX_  in 20 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 20 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (300 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 80 g Agela column to give (6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (2.85 g, 15.64 mmol, 68.889% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "14", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "17/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138825", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138825", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146066', 'AetherGen-prod-sdpo-8251', 'REF: Minmin Yang, Wei Ye, and Stewart W. Schneller, J . O r g . C h e m .2004, 6 9 , 3993-3996 To  COPPER(I) BROMIDE-DIMETHYL SULFID (408.33 mg, 1.99 mmol){{9:row 3}}_XXXXX_  in 80 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (28.3 mL, 28.38 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (3.5 g, 22.7 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (5.76 mL, 45.41 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (10.5 mL, 60.35 mmol){{9:row 4}}_XXXXX_  in 20 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 20 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (300 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 80 g Agela column to give (6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (2.85 g, 15.64 mmol, 68.889% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "14", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "17/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138825", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138825", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146049', 'AetherGen-masks', 'To 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 6-Chloropyridine-2,3-diamine (110.0 mg, 0.77 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction was diluted with water, extracted with ethyl acetate, the EtOAc layer was washed with water, brine, dried over sodium sulfate, filterred and concentrated. The crude was triturated with DCM, and the solid obtained was filtered. The solid was washed with ethyl acetate, DCM  to give 2-(4-benzyloxyphenyl)-5-chloro-3H-imidazo[4,5-b]pyridine (68 mg, 0.20251 mmol, 26.431% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "13", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138808", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138808", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146049', 'AetherGen-prod-sdpo-8251', 'To 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 6-Chloropyridine-2,3-diamine (110.0 mg, 0.77 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction was diluted with water, extracted with ethyl acetate, the EtOAc layer was washed with water, brine, dried over sodium sulfate, filterred and concentrated. The crude was triturated with DCM, and the solid obtained was filtered. The solid was washed with ethyl acetate, DCM  to give 2-(4-benzyloxyphenyl)-5-chloro-3H-imidazo[4,5-b]pyridine (68 mg, 0.20251 mmol, 26.431% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "13", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138808", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138808", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146048', 'AetherGen-masks', 'To 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 2,3-Diamino-5-chloropyridine (110.0 mg, 0.77 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction mixture showed lot of precipitate, which was filtered, the  filtrate was concentrated and extracted with ethyl acetate. The organic layer was washed with saturarted sodium bicarbonate, water, brine and dried over sodium sulfate, filtered and concentrated. The filtered solid washed with ethyl acetate, and dried under vacuum. The LC/MS indicated presence of desired product, but had impurity. The solid was not further purified. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "12", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138807", "MODIFIED_DATE": "20/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138807", "COUNTERSIGNED_DATE": "20/11/2016"}', '2025-02-03');
