INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146047', 'AetherGen-masks', 'A 5 mL vial with crimped Teflon septum containing cuprous;iodide (0.0 mL, 0.05 mmol){{9:row 2}}_XXXXX_ , palladium;triphenylphosphane (16.0 mg, 0.01 mmol){{9:row 1}}_XXXXX_ , and  N,N-diethylethanamine (0.21 mL, 1.51 mmol){{9:row 3}}_XXXXX_  under Ar was charged with DMF (1 mL){{3:row 1}}_XXXXX_ , and sparged with Ar for 2 min. The mixture was charged with ethynyl(trimethyl)silane (0.14 mL, 1.01 mmol){{9:row 5}}_XXXXX_  dropwise over 30 s, and stirred at RT for 24 h, then stored at 4 °C for 2.75 d. The mixture was diluted with 3 mL DCM, vacuum filtered through short SiO2 plug and glass frit and then rinsed with 50 mL DCM. Fractions were combined, concentrated under reduced pressure to give crude RAL001B. A 5 mL vial containing RAL001B was charged with methanol (15mL) followed by potassiooxycarbonyloxypotassium (95.0 mg, 0.69 mmol){{9:row 6}}_XXXXX_ potassiooxycarbonyloxypotassium (95.0 mg, 0.69 mmol){{9:row 6}}_XXXXX_  and then stirred at RT for 1 h. The mixture was diluted with DCM, filtered through a short SiO2 plug and glass frit then rinsed with 50 mL DCM. Fractions were combined, concentrated under reduced pressure and heat (40 °C), and purified by flash chromatography (12g column, 0-&gt;15% MeOH in DCM). The desired fractions were combined and concentrated under reduced pressure to yield RAL001C (2R,3R,4S,5R)-2-[4-amino-5-(2-trimethylsilylethynyl)pyrrolo[2,3-d]pyrimidin-7-yl]-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (47 mg, 0.12967 mmol, 50.85% yield){{2:row 1}}_XXXXX_  as a brown solid. TMS cleavage was unsuccessful.   Rf = .35 (10% MeOH in DCM)     Reaction start @ RT 5:50 p.m. 10/13/16 clear orange sol''n Opened @12:00 p.m. 10/14/16 dark orange Placed @ 4°C 6 p.m. 10/14/16 darker orange Retrieved @ RT 11:30 a.m. 10/17/16 black opaque; TLC shows consumption of SM Started @ RT 4:45 p.m. black opaque 6 p.m. filtered 7 p.m. @ 4°C 10/18/16 Purified by Isco LC   Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood. [AetherGen LIMS Verified]', '{"BOOK": "10", "ISID": "t.tra", "PAGE": "1", "DESCR": "Sonogashira coupling of Iodo-PRP with TMS acetylene", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138806", "MODIFIED_DATE": "31/10/2016", "COMPLETED_DATE": "26/10/2016", "COMPLETED_ISID": "t.tra", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138806", "COUNTERSIGNED_DATE": "31/10/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146030', 'AetherGen-prod-sdpo-8251', 'REF: Minmin Yang, Wei Ye, and Stewart W. Schneller, J . O r g . C h e m .2004, 6 9 , 3993-3996 To (6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1.15 g, 6.31 mmol){{9:row 1}}_XXXXX_  in 6 mL of anhydrous THF , cooled to 0 oC under an atmosphere of nitrogen was added a solution of lithium;alumanuide (479.01 mg, 12.62 mmol){{9:row 2}}_XXXXX_   in 25 mLof THF dropwise. The reaction was slowly allowed to warm to room temperature and stirred for 3 h. The reaction was cooled back to 0 oC and quenched with 0.5 mL of water, followed by 0.5 mL of 15 % NaOH, and additional 1.5 mL of water and stirred for 30 mins. The reaction mixture was filtered through Celite, filtrate washed with ethyl acetate and concentrtaed under vacuum. The crude residue was purified by silica gel chromatography using 0-40% EtOAc in hexane on a 40 g Agela column to give two fractions. The less polar product is desired(6R,6aR)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-ol (830 mg, 4.5052 mmol, 71.386% yield){{2:row 1}}_XXXXX_  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "10", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "07/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138789", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138789", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146047', 'AetherGen-prod-sdpo-8251', 'A 5 mL vial with crimped Teflon septum containing cuprous;iodide (0.0 mL, 0.05 mmol){{9:row 2}}_XXXXX_ , palladium;triphenylphosphane (16.0 mg, 0.01 mmol){{9:row 1}}_XXXXX_ , and  N,N-diethylethanamine (0.21 mL, 1.51 mmol){{9:row 3}}_XXXXX_  under Ar was charged with DMF (1 mL){{3:row 1}}_XXXXX_ , and sparged with Ar for 2 min. The mixture was charged with ethynyl(trimethyl)silane (0.14 mL, 1.01 mmol){{9:row 5}}_XXXXX_  dropwise over 30 s, and stirred at RT for 24 h, then stored at 4 °C for 2.75 d. The mixture was diluted with 3 mL DCM, vacuum filtered through short SiO2 plug and glass frit and then rinsed with 50 mL DCM. Fractions were combined, concentrated under reduced pressure to give crude RAL001B. A 5 mL vial containing RAL001B was charged with methanol (15mL) followed by potassiooxycarbonyloxypotassium (95.0 mg, 0.69 mmol){{9:row 6}}_XXXXX_ potassiooxycarbonyloxypotassium (95.0 mg, 0.69 mmol){{9:row 6}}_XXXXX_  and then stirred at RT for 1 h. The mixture was diluted with DCM, filtered through a short SiO2 plug and glass frit then rinsed with 50 mL DCM. Fractions were combined, concentrated under reduced pressure and heat (40 °C), and purified by flash chromatography (12g column, 0-&gt;15% MeOH in DCM). The desired fractions were combined and concentrated under reduced pressure to yield RAL001C (2R,3R,4S,5R)-2-[4-amino-5-(2-trimethylsilylethynyl)pyrrolo[2,3-d]pyrimidin-7-yl]-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (47 mg, 0.12967 mmol, 50.85% yield){{2:row 1}}_XXXXX_  as a brown solid. TMS cleavage was unsuccessful.   Rf = .35 (10% MeOH in DCM)     Reaction start @ RT 5:50 p.m. 10/13/16 clear orange sol''n Opened @12:00 p.m. 10/14/16 dark orange Placed @ 4°C 6 p.m. 10/14/16 darker orange Retrieved @ RT 11:30 a.m. 10/17/16 black opaque; TLC shows consumption of SM Started @ RT 4:45 p.m. black opaque 6 p.m. filtered 7 p.m. @ 4°C 10/18/16 Purified by Isco LC   Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood. [AetherGen LIMS Verified]', '{"BOOK": "10", "ISID": "t.tra", "PAGE": "1", "DESCR": "Sonogashira coupling of Iodo-PRP with TMS acetylene", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "13/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138806", "MODIFIED_DATE": "31/10/2016", "COMPLETED_DATE": "26/10/2016", "COMPLETED_ISID": "t.tra", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138806", "COUNTERSIGNED_DATE": "31/10/2016"}', '2025-02-03');
