INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146028', 'AetherGen-masks', 'To 4-Chloropyridine-2,3-diamine (110.0 mg, 0.77 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction was diluted with water, extracted with ethyl acetate, the EtOAc layer was washed with water, brine, dried over sodium sulfate, filterred and concentrated. The crude triturated with DCM to give a solid that was filtered. The solid was washed with EtOAc, DCM to give 2-(4-benzyloxyphenyl)-7-chloro-3H-imidazo[4,5-b]pyridine (60 mg, 0.17868 mmol, 23.321% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "9", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138787", "MODIFIED_DATE": "15/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138787", "COUNTERSIGNED_DATE": "15/11/2016"}', '2025-02-03');
