INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145980', 'AetherGen-masks', 'A solution of [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methanol (1500.0 mg, 4.88 mmol){{9:row 1}}_XXXXX_  , Tosyl chloride (1023.62 mg, 5.37 mmol){{9:row 2}}_XXXXX_  in Pyridine (10 mL){{3:row 1}}_XXXXX_  was stirred at RT over weekend. Solid was formed, which was soluble in water. The reaction mixture was concentrated, taken into sat. NaHCO3 (aq.) and EtOAc. The organic layer was washed with brine, dried to give 0.8 g of white foamy solid with ~20% starting alcohol based on TLC (9:1 DCM/MeOH). The crude mixture was taken to next step w/o purification. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "16", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138739", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138739", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-02-03');
