INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145966', 'AetherGen-masks', 'A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.0 mg, 0.22 mmol){{9:row 4}}_XXXXX_  (Int-5 from Medicilon), dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 2}}_XXXXX_   , dicesium;carbonate (72.68 mg, 0.22 mmol){{9:row 1}}_XXXXX_   1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in 1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in a pressure reaction tube (10 mL, MW) was purged with N2. 2,4,6-trimethyl-1,3,5,2,4,6-trioxatriborinane (0.13 mL, 0.45 mmol){{9:row 3}}_XXXXX_   was added. The tube was sealed and heated at 80 °C{{8:row 1}}_XXXXX_   . The color turned from dark orange to light orange. TLC van''t tell if any product formed. HNMR showed only starting material. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "14", "DESCR": "Suzuki reaction of Int-5 to 6-Me", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138725", "MODIFIED_DATE": "10/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138725", "COUNTERSIGNED_DATE": "10/10/2016"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145979', 'AetherGen-masks', 'To  COPPER(I) BROMIDE-DIMETHYL SULFID (175.0 mg, 0.85 mmol){{9:row 3}}_XXXXX_  in 40 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (12.2 mL, 12.16 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (1.5 g, 9.73 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (2.6 mL, 9.73 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (4.5 mL, 25.86 mmol){{9:row 4}}_XXXXX_  in 10 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 10 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (150 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 40 g Agela column to give (3aR,6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1260 mg, 6.9147 mmol, 71.065% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "8", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138738", "MODIFIED_DATE": "19/02/2017", "COMPLETED_DATE": "17/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138738", "COUNTERSIGNED_DATE": "19/02/2017"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145979', 'AetherGen-prod-sdpo-8251', 'To  COPPER(I) BROMIDE-DIMETHYL SULFID (175.0 mg, 0.85 mmol){{9:row 3}}_XXXXX_  in 40 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (12.2 mL, 12.16 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (1.5 g, 9.73 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (2.6 mL, 9.73 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (4.5 mL, 25.86 mmol){{9:row 4}}_XXXXX_  in 10 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 10 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (150 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 40 g Agela column to give (3aR,6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1260 mg, 6.9147 mmol, 71.065% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "8", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138738", "MODIFIED_DATE": "19/02/2017", "COMPLETED_DATE": "17/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138738", "COUNTERSIGNED_DATE": "19/02/2017"}', '2025-02-03');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145978', 'AetherGen-masks', 'To 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170.0 mg, 0.5 mmol){{9:row 1}}_XXXXX_  in 6 mL of THF under nitrogen was added the (Diacetoxyiodo)benzene (194.52 mg, 0.6 mmol){{9:row 2}}_XXXXX_  and the reaction stirred at room temperature for 16 h. The reaction was mixture was concentrated, extracted with ethyl acetate, the EtOAc layer was washed with  saturated sodium bicarbonate. The organic layer was washed with brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using 0-100% EtOAc in hexane to give 2-(4-benzyloxyphenyl)-7-chloro-3H-imidazo[4,5-b]pyridine (5 mg, 0.01489 mmol, 2.9588% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "7", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138737", "MODIFIED_DATE": "15/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138737", "COUNTERSIGNED_DATE": "15/11/2016"}', '2025-02-03');
