INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145966', 'AetherGen-prod-sdpo-8251', 'A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.0 mg, 0.22 mmol){{9:row 4}}_XXXXX_  (Int-5 from Medicilon), dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 2}}_XXXXX_   , dicesium;carbonate (72.68 mg, 0.22 mmol){{9:row 1}}_XXXXX_   1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in 1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in a pressure reaction tube (10 mL, MW) was purged with N2. 2,4,6-trimethyl-1,3,5,2,4,6-trioxatriborinane (0.13 mL, 0.45 mmol){{9:row 3}}_XXXXX_   was added. The tube was sealed and heated at 80 °C{{8:row 1}}_XXXXX_   . The color turned from dark orange to light orange. TLC van''t tell if any product formed. HNMR showed only starting material. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "14", "DESCR": "Suzuki reaction of Int-5 to 6-Me", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138725", "MODIFIED_DATE": "10/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138725", "COUNTERSIGNED_DATE": "10/10/2016"}', '2025-02-03');
