INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145947', 'AetherGen-masks', 'A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   , azetidine-3-carbonitrile hydrochloride (58.95 mg, 0.5 mmol){{9:row 2}}_XXXXX_   and  N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   inIPA (0.50 mL){{3:row 1}}_XXXXX_   was heated at 88 °C{{8:row 1}}_XXXXX_   overnight. TLC showed almost completion of reaction. The reaction mixture was loaded on a 12g column, vaccum dried and eluted with 10:1 EtOAc and MeOH to give 1-[6-amino-9-[(2R,3R,4S,5R)-3,4-dihydroxy-5-(hydroxymethyl)tetrahydrofuran-2-yl]purin-2-yl]azetidine-3-carbonitrile (50 mg, 0.14396 mmol, 86.86% yield){{2:row 1}}_XXXXX_   as a white solid (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_     [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "9", "DESCR": "2-Cl adenosine replacement with CN-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_001", "EXPERIMENT_ID": "138706", "MODIFIED_DATE": "06/10/2016", "COMPLETED_DATE": "06/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138706", "COUNTERSIGNED_DATE": "06/10/2016"}', '2025-02-03');
