INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145945', 'AetherGen-masks', 'REF: WO 2014/128465  To 4-chloropyridine-2,3-diamine (0.1 g, 0.7 mmol){{9:row 1}}_XXXXX_  in 4-benzyloxybenzaldehyde (0.17 g, 0.8 mmol){{9:row 2}}_XXXXX_  in 20 mL of water was heated at 100 oC for 18 h. The reaction was extracted cooled to room temperature, extracted with ethyl acetate,  and the layers seperated. The organic layer was washed with water, brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using a Agela 20 g, column, eluting with 0-20% EtOAc in hexane to give 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170 mg, 0.50326 mmol, 72.253% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "5", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "22/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138704", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138704", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-03');
