INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145888', 'AetherGen-masks', ' A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.mg, 0.2200mmol), cyclopropylboronic acid (38.32 mg, 0.45 mmol){{9:row 2}}_XXXXX_     , dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 4}}_XXXXX_   , and dipotassium carbonate (37.0 mg, 0.27 mmol){{9:row 3}}_XXXXX_     in 1,4-Dioxane (1.5 mL){{3:row 1}}_XXXXX_     was flushed with nitrogen, sealed and heated at 100 C overnight. TLC (1:1 Hexane:EtOAc, starting material Rf 0.5) showed new spots formed. The reaction was cooled down, filtered with celite, rinse with EtOAc, concentrated and the residue was eluted with 10-40% of EtOAc in hexane. The fractions were combined, evaporated. The HNMR (HL001-7-1A) showed mainly starting material, a little bit product. Discarded.INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145888', 'AetherGen-prod-sdpo-8251', ' A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.mg, 0.2200mmol), cyclopropylboronic acid (38.32 mg, 0.45 mmol){{9:row 2}}_XXXXX_     , dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 4}}_XXXXX_   , and dipotassium carbonate (37.0 mg, 0.27 mmol){{9:row 3}}_XXXXX_     in 1,4-Dioxane (1.5 mL){{3:row 1}}_XXXXX_     was flushed with nitrogen, sealed and heated at 100 C overnight. TLC (1:1 Hexane:EtOAc, starting material Rf 0.5) showed new spots formed. The reaction was cooled down, filtered with celite, rinse with EtOAc, concentrated and the residue was eluted with 10-40% of EtOAc in hexane. The fractions were combined, evaporated. The HNMR (HL001-7-1A) showed 