INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146015', 'AetherGen', 'A mixture of[(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (100.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_ , 3-fluoroazetidine hydrochloride (38.67 mg, 0.35 mmol){{9:row 2}}_XXXXX_ ,  potassiooxycarbonyloxypotassium (47.92 mg, 0.35 mmol){{9:row 3}}_XXXXX_  in IPA (1 mL){{3:row 1}}_XXXXX_  was heated at 80 °C{{8:row 1}}_XXXXX_  overnight. The TLC showed OTs was hydrolyzed back to OH. This reaction can''t use TEA as base as it forms stable ammonium salt. Hunig base would be used for this type of reaction. Discard This target was not pursued further due to azetine analog MD-0041/PRT1000096 was inactive [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "17", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "03/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138774", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138774", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145980', 'AetherGen', 'A solution of [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methanol (1500.0 mg, 4.88 mmol){{9:row 1}}_XXXXX_  , Tosyl chloride (1023.62 mg, 5.37 mmol){{9:row 2}}_XXXXX_  in Pyridine (10 mL){{3:row 1}}_XXXXX_  was stirred at RT over weekend. Solid was formed, which was soluble in water. The reaction mixture was concentrated, taken into sat. NaHCO3 (aq.) and EtOAc. The organic layer was washed with brine, dried to give 0.8 g of white foamy solid with ~20% starting alcohol based on TLC (9:1 DCM/MeOH). The crude mixture was taken to next step w/o purification. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "16", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138739", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138739", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145867', 'AetherGen', 'A mixture of (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(chloromethyl)tetrahydrofuran-3,4-diol (300.0 mg, 1.05 mmol){{9:row 1}}_XXXXX_   , methylaminoacetonitrile hydrochloride salt (100.0 mg, 0.35 mmol){{9:row 2}}_XXXXX_   , sodium iodide (10.49 mg, 0.07 mmol){{9:row 3}}_XXXXX_   and N,N-diethylethanamine (0.05 mL, 0.35 mmol){{9:row 4}}_XXXXX_   in IPA (1 mL){{3:row 1}}_XXXXX_   was heated at 50 °C{{8:row 1}}_XXXXX_   overnight. No new spot was formed. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "5", "DESCR": "5''-Cl replacement with nitrile-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "09/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138626", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "03/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138626", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145979', 'AetherGen', 'To  COPPER(I) BROMIDE-DIMETHYL SULFID (175.0 mg, 0.85 mmol){{9:row 3}}_XXXXX_  in 40 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (12.2 mL, 12.16 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (1.5 g, 9.73 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (2.6 mL, 9.73 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (4.5 mL, 25.86 mmol){{9:row 4}}_XXXXX_  in 10 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 10 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (150 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 40 g Agela column to give (3aR,6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1260 mg, 6.9147 mmol, 71.065% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "8", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138738", "MODIFIED_DATE": "19/02/2017", "COMPLETED_DATE": "17/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138738", "COUNTERSIGNED_DATE": "19/02/2017"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145978', 'AetherGen', 'To 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170.0 mg, 0.5 mmol){{9:row 1}}_XXXXX_  in 6 mL of THF under nitrogen was added the (Diacetoxyiodo)benzene (194.52 mg, 0.6 mmol){{9:row 2}}_XXXXX_  and the reaction stirred at room temperature for 16 h. The reaction was mixture was concentrated, extracted with ethyl acetate, the EtOAc layer was washed with  saturated sodium bicarbonate. The organic layer was washed with brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using 0-100% EtOAc in hexane to give 2-(4-benzyloxyphenyl)-7-chloro-3H-imidazo[4,5-b]pyridine (5 mg, 0.01489 mmol, 2.9588% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "7", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138737", "MODIFIED_DATE": "15/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138737", "COUNTERSIGNED_DATE": "15/11/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145967', 'AetherGen', 'borane;sodium hydride (11.21 mg, 0.3 mmol){{9:row 2}}_XXXXX_  was added to a suspension of  9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]purin-6-amine (50.0 mg, 0.15 mmol){{9:row 1}}_XXXXX_    in Methanol (1 mL){{3:row 1}}_XXXXX_   at RT. The gas bubbles observed. The reaction mixture remained as suspension. TLC can''t tell if the reaction occurred after an aliquot was treated with Sat. NH4Cl aq., whcih was extracted with EtOAc. NH2 likely need to be protected. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "15", "DESCR": "Reduction of purine with NaBH4---Int-3", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138726", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138726", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145966', 'AetherGen', 'A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.0 mg, 0.22 mmol){{9:row 4}}_XXXXX_  (Int-5 from Medicilon), dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 2}}_XXXXX_   , dicesium;carbonate (72.68 mg, 0.22 mmol){{9:row 1}}_XXXXX_   1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in 1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in a pressure reaction tube (10 mL, MW) was purged with N2. 2,4,6-trimethyl-1,3,5,2,4,6-trioxatriborinane (0.13 mL, 0.45 mmol){{9:row 3}}_XXXXX_   was added. The tube was sealed and heated at 80 °C{{8:row 1}}_XXXXX_   . The color turned from dark orange to light orange. TLC van''t tell if any product formed. HNMR showed only starting material. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "14", "DESCR": "Suzuki reaction of Int-5 to 6-Me", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138725", "MODIFIED_DATE": "10/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138725", "COUNTERSIGNED_DATE": "10/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145965', 'AetherGen', 'borane;sodium hydride (12.72 mg, 0.34 mmol){{9:row 2}}_XXXXX_   borane;sodium hydride (12.72 mg, 0.34 mmol){{9:row 2}}_XXXXX_  was added to a suspension of (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(methylsulfanylmethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(methylsulfanylmethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (MD-0004 second batch) in  Methanol (1 mL){{3:row 1}}_XXXXX_  at RT. The gas bubbles observed. The reaction mixture became clear. TLC can''t tell if the reaction occurred after an aliquot was treated with Sat. NH4Cl aq., whcih was extracted with EtOAc. Since NH2 was protected in the reported reactions, this was discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "13", "DESCR": "Reduction of purine with NaBH4", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138724", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138724", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
