INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145947', 'AetherGen', 'A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   , azetidine-3-carbonitrile hydrochloride (58.95 mg, 0.5 mmol){{9:row 2}}_XXXXX_   and  N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   inIPA (0.50 mL){{3:row 1}}_XXXXX_   was heated at 88 °C{{8:row 1}}_XXXXX_   overnight. TLC showed almost completion of reaction. The reaction mixture was loaded on a 12g column, vaccum dried and eluted with 10:1 EtOAc and MeOH to give 1-[6-amino-9-[(2R,3R,4S,5R)-3,4-dihydroxy-5-(hydroxymethyl)tetrahydrofuran-2-yl]purin-2-yl]azetidine-3-carbonitrile (50 mg, 0.14396 mmol, 86.86% yield){{2:row 1}}_XXXXX_   as a white solid (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_     [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "9", "DESCR": "2-Cl adenosine replacement with CN-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_001", "EXPERIMENT_ID": "138706", "MODIFIED_DATE": "06/10/2016", "COMPLETED_DATE": "06/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138706", "COUNTERSIGNED_DATE": "06/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145946', 'AetherGen', 'N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_  was added to a mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  and 3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_  in IPA (0.50 mL){{3:row 1}}_XXXXX_  . The resulting mixture was sealed and heated at 88 °C{{8:row 1}}_XXXXX_  over night. TLC showed remaining starting material closed eluted with product (more polar, bright blue on TLC) in 10% MeOH in EtOAc. The reaction mixture was concentrated, loaded on a 20 g silica gel column and purified to give (2R,3R,4S,5R)-2-[6-amino-2-(3-fluoroazetidin-1-yl)purin-9-yl]-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (12 mg, 0.03174 mmol, 19.149% yield){{2:row 1}}_XXXXX_   as white solid. HNMR showed about 10% starting material was contaminated.(2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_    C12H16N4O3SN,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   was added to A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_    88 °C{{8:row 1}}_XXXXX_   IPA (0.50 mL){{3:row 1}}_XXXXX_    [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "8", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138705", "MODIFIED_DATE": "07/10/2016", "COMPLETED_DATE": "04/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138705", "COUNTERSIGNED_DATE": "07/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145945', 'AetherGen', 'REF: WO 2014/128465  To 4-chloropyridine-2,3-diamine (0.1 g, 0.7 mmol){{9:row 1}}_XXXXX_  in 4-benzyloxybenzaldehyde (0.17 g, 0.8 mmol){{9:row 2}}_XXXXX_  in 20 mL of water was heated at 100 oC for 18 h. The reaction was extracted cooled to room temperature, extracted with ethyl acetate,  and the layers seperated. The organic layer was washed with water, brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using a Agela 20 g, column, eluting with 0-20% EtOAc in hexane to give 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170 mg, 0.50326 mmol, 72.253% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "5", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "22/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138704", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138704", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145888', 'AetherGen', ' A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.mg, 0.2200mmol), cyclopropylboronic acid (38.32 mg, 0.45 mmol){{9:row 2}}_XXXXX_     , dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 4}}_XXXXX_   , and dipotassium carbonate (37.0 mg, 0.27 mmol){{9:row 3}}_XXXXX_     in 1,4-Dioxane (1.5 mL){{3:row 1}}_XXXXX_     was flushed with nitrogen, sealed and heated at 100 C overnight. TLC (1:1 Hexane:EtOAc, starting material Rf 0.5) showed new spots formed. The reaction was cooled down, filtered with celite, rinse with EtOAc, concentrated and the residue was eluted with 10-40% of EtOAc in hexane. The fractions were combined, evaporated. The HNMR (HL001-7-1A) showed mainly starting material, a little bit product. Discarded.INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145852', 'AetherGen', 'To [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methanol (0.5 g, 1.63 mmol){{9:row 1}}_XXXXX_  in 10 mL of anhydrous pyridine at 0 oC was added the Tosyl chloride (0.25 mL, 1.79 mmol){{9:row 2}}_XXXXX_  and stirred at room temperature for 16 h. The reaction mixture was dilted with water, extracted with DCM. THe DCM layer was seperated, washed with water, dried over sodium sulfate, filtered and concentrated. The crude was used in next step without further purification. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "1", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138611", "MODIFIED_DATE": "19/10/2016", "COMPLETED_DATE": "13/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138611", "COUNTERSIGNED_DATE": "19/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145847', 'AetherGen', 'A mixture of ? (100.mg, 0.3500mmol)  sodium iodide (10.49 mg, 0.07 mmol){{9:row 2}}_XXXXX_   ), sodium iodide (10.49 mg, 0.07 mmol){{9:row 2}}_XXXXX_  , N,N-diethylethanamine (0.05 mL, 0.35 mmol){{9:row 3}}_XXXXX_  and (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(chloromethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.18 mmol){{9:row 4}}_XXXXX_  in IPA (? mL){{3:row 1}}_XXXXX_  was heated at 50 C over 72 hrs. No new spot was observed on TLC. Discarded3-Fluoroazetidine hydrochloride (117.14 mg, 1.05 mmol){{9:row 1}}_XXXXX_   3-Fluoroazetidine hydrochloride (117.14 mg, 1.05 mmol){{9:row 1}}_XXXXX_       [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "2", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "05/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138606", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "03/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138606", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145845', 'AetherGen', ' These compounds were purchased to be tested in RBC PRMT5/MEP50 HotPlate assay. They''re were labeled PCM-001 to PCM-010. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "1", "DESCR": "Registration of commercial adenosine analogs", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "04/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138604", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "03/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138604", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145684', 'AetherGen', '[(22S,23R,24S,25R,26S,27R,37S,38S,39S)-39-acetoxy-24-[(2R,3S)-3-amino-2-hydroxy-3-(p-tolyl)propanoyl]oxy-22,27,38-trihydroxy-28,36,36,37-tetramethyl-30-oxo-49-oxatetracyclo[BLAH.BLAH.BLAH.BLAH.BLAH]heptadec-28-en-26-yl] benzoate (190.0 mg, 0.26 mmol){{9:row 1}}_XXXXX_  was added to DCM (200 mL){{3:row 1}}_XXXXX_  andditert-butyl carbonate (67.0 mg, 0.38 mmol){{9:row 2}}_XXXXX_  added to make  [(25S,26R,27S,28R,29S,30R,41S,42S,43S)-43-acetoxy-27-[(2R,3S)-3-(tert-butoxycarbonylamino)-2-hydroxy-3-(p-tolyl)propanoyl]oxy-25,30,42-trihydroxy-31,40,40,41-tetramethyl-33-oxo-55-oxatetracyclo[BLAH.BLAH.BLAH.BLAH.BLAH]heptadec-31-en-29-yl] benzoate (100 mg, 0.12167 mmol, ?% yield){{2:row 1}}_XXXXX_  [AetherGen LIMS Verified]', '{"BOOK": "1", "ISID": "bio_root", "PAGE": "1", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/03/2013", "COUNTERSIGNER": "scientist_000", "EXPERIMENT_ID": "138443", "MODIFIED_DATE": "27/08/2024", "COMPLETED_ISID": "guest.user", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138443"}', '2025-02-11');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('196343', 'AetherGen-masks2', 'To a solution of  N-methylthiophene-3-carboxamide (​350.0 mg, ​2.48 mmol)​{{1080:row 1}}_XXXXX_   in THF (7 mL){{3:row 1}}_XXXXX_   was added sodium hydride (​118.99 mg, ​2.97 mmol)​{{1080:row 3}}_XXXXX_    at -65°C. Then n-Butyllithium (​2.97 mL, ​7.44 mmol)​{{1080:row 2}}_XXXXX_   was added dropwise at -65 °C under N2. The N,N-dimethylformamide, extra dry over M.S. (​905.92 mg, ​12.39 mmol)​{{1080:row 4}}_XXXXX_  was added at -65°C.The reaction mixture was stirred at 20 °C for 8 hrs   The crude was checked by HPLC, showing 45.68% conversion.  The reaction mixture was quenched with saturated aqueous NH4Cl. The resulting solution was extracted with EA(50mL*2) and DCM(50mL*1). The organic phase were combined and dried over Na2SO4, then filtered and the filtrate was concentrated under reduced pressure to give a residue.       The crude(2-formyl-N-methylthiophene-3-carboxamide (450 mg, 1.2154 mmol, 49.03% yield){{2:row 1}}_XXXXX_  ) was uesd for next step directly. [AetherGen LIMS Verified]', '{"BOOK": "720", "ISID": "k.ke1", "PAGE": "7", "STATUS": "0", "PROTOCOL": "CRO_Affinity_Wuhan", "PROTOCOL_ID": "481", "CREATED_DATE": "01/11/2021", "COUNTERSIGNER": "scientist_000", "EXPERIMENT_ID": "189102", "MODIFIED_DATE": "23/12/2021", "COMPLETED_ISID": "guest.user", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "189102"}', '2025-02-18');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146015', 'AetherGen-masks2', 'A mixture of[(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (100.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_ , 3-fluoroazetidine hydrochloride (38.67 mg, 0.35 mmol){{9:row 2}}_XXXXX_ ,  potassiooxycarbonyloxypotassium (47.92 mg, 0.35 mmol){{9:row 3}}_XXXXX_  in IPA (1 mL){{3:row 1}}_XXXXX_  was heated at 80 °C{{8:row 1}}_XXXXX_  overnight. The TLC showed OTs was hydrolyzed back to OH. This reaction can''t use TEA as base as it forms stable ammonium salt. Hunig base would be used for this type of reaction. Discard This target was not pursued further due to azetine analog MD-0041/PRT1000096 was inactive [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "17", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "03/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138774", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138774", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145980', 'AetherGen-masks2', 'A solution of [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methanol (1500.0 mg, 4.88 mmol){{9:row 1}}_XXXXX_  , Tosyl chloride (1023.62 mg, 5.37 mmol){{9:row 2}}_XXXXX_  in Pyridine (10 mL){{3:row 1}}_XXXXX_  was stirred at RT over weekend. Solid was formed, which was soluble in water. The reaction mixture was concentrated, taken into sat. NaHCO3 (aq.) and EtOAc. The organic layer was washed with brine, dried to give 0.8 g of white foamy solid with ~20% starting alcohol based on TLC (9:1 DCM/MeOH). The crude mixture was taken to next step w/o purification. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "16", "DESCR": "Tosylation", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138739", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138739", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145979', 'AetherGen-masks2', 'To  COPPER(I) BROMIDE-DIMETHYL SULFID (175.0 mg, 0.85 mmol){{9:row 3}}_XXXXX_  in 40 mL of anhydrous THF at -78 o C under atmosphere of nitrogen was added the VINYLMAGNESIUM BROMIDE, 1.0M SOLUTION (12.2 mL, 12.16 mmol){{9:row 2}}_XXXXX_  and stirred for 10 mins. To this was added the(3aR,6aR)-3a,6a-dihydro-2,2-dimethyl-4H-cyclopenta-1,3-dioxol-4-one (1.5 g, 9.73 mmol){{9:row 1}}_XXXXX_ , chloro(trimethyl)silane (2.6 mL, 9.73 mmol){{9:row 5}}_XXXXX_  and N-[bis(dimethylamino)phosphoryl]-N-methyl-methanamine (4.5 mL, 25.86 mmol){{9:row 4}}_XXXXX_  in 10 mL of THF. The reaction mixture was stirred at -78 oC for 3 h, and then warmed to 0 oC, quenched iwth 10 mL of saturated NH4Cl. The reaction mixture was stirred for 30 mins, extracted with ethyl acetate (150 mL). the organic layer was seperated, washed with water, brine, dried over sodium sulfate, filtered and concentrated. the crude was purified by silica gel chromatography using 0-20 % EtOAc in hexane on a 40 g Agela column to give (3aR,6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1260 mg, 6.9147 mmol, 71.065% yield){{2:row 1}}_XXXXX_ . Standard Controls Apply: Lab coats, gloves and safety specs are to be worn at all times. All experiments should be performed in a fumehood.  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "8", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138738", "MODIFIED_DATE": "19/02/2017", "COMPLETED_DATE": "17/01/2017", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138738", "COUNTERSIGNED_DATE": "19/02/2017"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145978', 'AetherGen-masks2', 'To 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170.0 mg, 0.5 mmol){{9:row 1}}_XXXXX_  in 6 mL of THF under nitrogen was added the (Diacetoxyiodo)benzene (194.52 mg, 0.6 mmol){{9:row 2}}_XXXXX_  and the reaction stirred at room temperature for 16 h. The reaction was mixture was concentrated, extracted with ethyl acetate, the EtOAc layer was washed with  saturated sodium bicarbonate. The organic layer was washed with brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using 0-100% EtOAc in hexane to give 2-(4-benzyloxyphenyl)-7-chloro-3H-imidazo[4,5-b]pyridine (5 mg, 0.01489 mmol, 2.9588% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "7", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "30/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138737", "MODIFIED_DATE": "15/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138737", "COUNTERSIGNED_DATE": "15/11/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145967', 'AetherGen-masks2', 'borane;sodium hydride (11.21 mg, 0.3 mmol){{9:row 2}}_XXXXX_  was added to a suspension of  9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]purin-6-amine (50.0 mg, 0.15 mmol){{9:row 1}}_XXXXX_    in Methanol (1 mL){{3:row 1}}_XXXXX_   at RT. The gas bubbles observed. The reaction mixture remained as suspension. TLC can''t tell if the reaction occurred after an aliquot was treated with Sat. NH4Cl aq., whcih was extracted with EtOAc. NH2 likely need to be protected. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "15", "DESCR": "Reduction of purine with NaBH4---Int-3", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138726", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138726", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145966', 'AetherGen-masks2', 'A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.0 mg, 0.22 mmol){{9:row 4}}_XXXXX_  (Int-5 from Medicilon), dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 2}}_XXXXX_   , dicesium;carbonate (72.68 mg, 0.22 mmol){{9:row 1}}_XXXXX_   1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in 1,4-Dioxane (1 mL){{3:row 1}}_XXXXX_   in a pressure reaction tube (10 mL, MW) was purged with N2. 2,4,6-trimethyl-1,3,5,2,4,6-trioxatriborinane (0.13 mL, 0.45 mmol){{9:row 3}}_XXXXX_   was added. The tube was sealed and heated at 80 °C{{8:row 1}}_XXXXX_   . The color turned from dark orange to light orange. TLC van''t tell if any product formed. HNMR showed only starting material. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "14", "DESCR": "Suzuki reaction of Int-5 to 6-Me", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138725", "MODIFIED_DATE": "10/10/2016", "COMPLETED_DATE": "05/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138725", "COUNTERSIGNED_DATE": "10/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145965', 'AetherGen-masks2', 'borane;sodium hydride (12.72 mg, 0.34 mmol){{9:row 2}}_XXXXX_   borane;sodium hydride (12.72 mg, 0.34 mmol){{9:row 2}}_XXXXX_  was added to a suspension of (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(methylsulfanylmethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(methylsulfanylmethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (MD-0004 second batch) in  Methanol (1 mL){{3:row 1}}_XXXXX_  at RT. The gas bubbles observed. The reaction mixture became clear. TLC can''t tell if the reaction occurred after an aliquot was treated with Sat. NH4Cl aq., whcih was extracted with EtOAc. Since NH2 was protected in the reported reactions, this was discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "13", "DESCR": "Reduction of purine with NaBH4", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "29/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138724", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138724", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
