INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145955', 'AetherGen-masks2', 'A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  2-(methylamino)acetonitrile hydrochloride (52.98 mg, 0.5 mmol){{9:row 2}}_XXXXX_  ), 2-(methylamino)acetonitrile hydrochloride (52.98 mg, 0.5 mmol){{9:row 2}}_XXXXX_  , N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_  and  in IPA (0.50 mL){{3:row 1}}_XXXXX_  was heated at 88 °C{{8:row 1}}_XXXXX_  over 72 hrs. No new spot was observed on TLC. The reaction mixture was purified by FCC (12 g, 10% MeOH/EtOAc). The UV fractions are starting material based on HNMR. Discarded.(2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_     [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "12", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "26/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138714", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138714", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145949', 'AetherGen-masks2', 'This reaction was meant to set up with Formycin A. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "11", "DESCR": "Registration of commercial adenosine analogs", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138708", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138708", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
