INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145947', 'AetherGen-masks2', 'A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   , azetidine-3-carbonitrile hydrochloride (58.95 mg, 0.5 mmol){{9:row 2}}_XXXXX_   and  N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   inIPA (0.50 mL){{3:row 1}}_XXXXX_   was heated at 88 °C{{8:row 1}}_XXXXX_   overnight. TLC showed almost completion of reaction. The reaction mixture was loaded on a 12g column, vaccum dried and eluted with 10:1 EtOAc and MeOH to give 1-[6-amino-9-[(2R,3R,4S,5R)-3,4-dihydroxy-5-(hydroxymethyl)tetrahydrofuran-2-yl]purin-2-yl]azetidine-3-carbonitrile (50 mg, 0.14396 mmol, 86.86% yield){{2:row 1}}_XXXXX_   as a white solid (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_     [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "9", "DESCR": "2-Cl adenosine replacement with CN-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_001", "EXPERIMENT_ID": "138706", "MODIFIED_DATE": "06/10/2016", "COMPLETED_DATE": "06/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138706", "COUNTERSIGNED_DATE": "06/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145946', 'AetherGen-masks2', 'N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_  was added to a mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  and 3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_  in IPA (0.50 mL){{3:row 1}}_XXXXX_  . The resulting mixture was sealed and heated at 88 °C{{8:row 1}}_XXXXX_  over night. TLC showed remaining starting material closed eluted with product (more polar, bright blue on TLC) in 10% MeOH in EtOAc. The reaction mixture was concentrated, loaded on a 20 g silica gel column and purified to give (2R,3R,4S,5R)-2-[6-amino-2-(3-fluoroazetidin-1-yl)purin-9-yl]-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (12 mg, 0.03174 mmol, 19.149% yield){{2:row 1}}_XXXXX_   as white solid. HNMR showed about 10% starting material was contaminated.(2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_  (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_    C12H16N4O3SN,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07mL, 0.5000mmol) N,N-diethylethanamine (0.07 mL, 0.5 mmol){{9:row 3}}_XXXXX_   was added to A mixture of (2R,3R,4S,5R)-2-(6-amino-2-chloro-purin-9-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_   3-Fluoroazetidine hydrochloride (55.46 mg, 0.5 mmol){{9:row 2}}_XXXXX_    88 °C{{8:row 1}}_XXXXX_   IPA (0.50 mL){{3:row 1}}_XXXXX_    [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "8", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "23/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138705", "MODIFIED_DATE": "07/10/2016", "COMPLETED_DATE": "04/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138705", "COUNTERSIGNED_DATE": "07/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145945', 'AetherGen-masks2', 'REF: WO 2014/128465  To 4-chloropyridine-2,3-diamine (0.1 g, 0.7 mmol){{9:row 1}}_XXXXX_  in 4-benzyloxybenzaldehyde (0.17 g, 0.8 mmol){{9:row 2}}_XXXXX_  in 20 mL of water was heated at 100 oC for 18 h. The reaction was extracted cooled to room temperature, extracted with ethyl acetate,  and the layers seperated. The organic layer was washed with water, brine, dried over sodium sulfate, filtered and concentrated. The crude was purified by silica gel chromatography using a Agela 20 g, column, eluting with 0-20% EtOAc in hexane to give 3-[(E)-(4-benzyloxyphenyl)methyleneamino]-4-chloro-pyridin-2-amine (170 mg, 0.50326 mmol, 72.253% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "5", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "22/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138704", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138704", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145888', 'AetherGen-masks2', ' A mixture of 9-[(3aR,4R,6S,6aS)-2,2-dimethyl-6-(methylsulfanylmethyl)-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-4-yl]-6-iodo-purine (100.mg, 0.2200mmol), cyclopropylboronic acid (38.32 mg, 0.45 mmol){{9:row 2}}_XXXXX_     , dichloromethane;dichloropalladium;(1''-diphenylphosphanylferrocen-1-yl)-diphenyl-phosphane (5.0 mg, 0.01 mmol){{9:row 4}}_XXXXX_   , and dipotassium carbonate (37.0 mg, 0.27 mmol){{9:row 3}}_XXXXX_     in 1,4-Dioxane (1.5 mL){{3:row 1}}_XXXXX_     was flushed with nitrogen, sealed and heated at 100 C overnight. TLC (1:1 Hexane:EtOAc, starting material Rf 0.5) showed new spots formed. The reaction was cooled down, filtered with celite, rinse with EtOAc, concentrated and the residue was eluted with 10-40% of EtOAc in hexane. The fractions were combined, evaporated. The HNMR (HL001-7-1A) showed mainly starting material, a little bit product. Discarded.INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145867', 'AetherGen-masks2', 'A mixture of (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(chloromethyl)tetrahydrofuran-3,4-diol (300.0 mg, 1.05 mmol){{9:row 1}}_XXXXX_   , methylaminoacetonitrile hydrochloride salt (100.0 mg, 0.35 mmol){{9:row 2}}_XXXXX_   , sodium iodide (10.49 mg, 0.07 mmol){{9:row 3}}_XXXXX_   and N,N-diethylethanamine (0.05 mL, 0.35 mmol){{9:row 4}}_XXXXX_   in IPA (1 mL){{3:row 1}}_XXXXX_   was heated at 50 °C{{8:row 1}}_XXXXX_   overnight. No new spot was formed. Discarded [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "5", "DESCR": "5''-Cl replacement with nitrile-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "09/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138626", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "03/10/2016", "COMP