INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145853', 'AetherGen-masks2', 'To [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (750.0 mg, 1.63 mmol){{9:row 1}}_XXXXX_  in 20 mL of acetone was added the sodium;iodide (1217.98 mg, 8.13 mmol){{9:row 2}}_XXXXX_  and the mixture heated at 60 oC for 16 h. The reaction mixture was filtered throgh Celite, and concentrated under vacuum. The crude was used without further purification. [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "2", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138612", "MODIFIED_DATE": "19/10/2016", "COMPLETED_DATE": "13/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138612", "COUNTERSIGNED_DATE": "19/10/2016"}', '2025-02-20');
