INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145847', 'AetherGen-masks2', 'A mixture of ? (100.mg, 0.3500mmol)  sodium iodide (10.49 mg, 0.07 mmol){{9:row 2}}_XXXXX_   ), sodium iodide (10.49 mg, 0.07 mmol){{9:row 2}}_XXXXX_  , N,N-diethylethanamine (0.05 mL, 0.35 mmol){{9:row 3}}_XXXXX_  and (2R,3R,4S,5S)-2-(6-aminopurin-9-yl)-5-(chloromethyl)tetrahydrofuran-3,4-diol (50.0 mg, 0.18 mmol){{9:row 4}}_XXXXX_  in IPA (? mL){{3:row 1}}_XXXXX_  was heated at 50 C over 72 hrs. No new spot was observed on TLC. Discarded3-Fluoroazetidine hydrochloride (117.14 mg, 1.05 mmol){{9:row 1}}_XXXXX_   3-Fluoroazetidine hydrochloride (117.14 mg, 1.05 mmol){{9:row 1}}_XXXXX_       [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "2", "DESCR": "5''-Cl replacement with F-azetidine", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "05/09/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138606", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "03/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138606", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('145684', 'AetherGen-masks2', '[(22S,23R,24S,25R,26S,27R,37S,38S,39S)-39-acetoxy-24-[(2R,3S)-3-amino-2-hydroxy-3-(p-tolyl)propanoyl]oxy-22,27,38-trihydroxy-28,36,36,37-tetramethyl-30-oxo-49-oxatetracyclo[BLAH.BLAH.BLAH.BLAH.BLAH]heptadec-28-en-26-yl] benzoate (190.0 mg, 0.26 mmol){{9:row 1}}_XXXXX_  was added to DCM (200 mL){{3:row 1}}_XXXXX_  andditert-butyl carbonate (67.0 mg, 0.38 mmol){{9:row 2}}_XXXXX_  added to make  [(25S,26R,27S,28R,29S,30R,41S,42S,43S)-43-acetoxy-27-[(2R,3S)-3-(tert-butoxycarbonylamino)-2-hydroxy-3-(p-tolyl)propanoyl]oxy-25,30,42-trihydroxy-31,40,40,41-tetramethyl-33-oxo-55-oxatetracyclo[BLAH.BLAH.BLAH.BLAH.BLAH]heptadec-31-en-29-yl] benzoate (100 mg, 0.12167 mmol, ?% yield){{2:row 1}}_XXXXX_  [AetherGen LIMS Verified]', '{"BOOK": "1", "ISID": "bio_root", "PAGE": "1", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/03/2013", "COUNTERSIGNER": "scientist_000", "EXPERIMENT_ID": "138443", "MODIFIED_DATE": "27/08/2024", "COMPLETED_ISID": "guest.user", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138443"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146030', 'AetherGen-masks2', 'REF: Minmin Yang, Wei Ye, and Stewart W. Schneller, J . O r g . C h e m .2004, 6 9 , 3993-3996 To (6R,6aR)-2,2-dimethyl-6-vinyl-3a,5,6,6a-tetrahydrocyclopenta[d][1,3]dioxol-4-one (1.15 g, 6.31 mmol){{9:row 1}}_XXXXX_  in 6 mL of anhydrous THF , cooled to 0 oC under an atmosphere of nitrogen was added a solution of lithium;alumanuide (479.01 mg, 12.62 mmol){{9:row 2}}_XXXXX_   in 25 mLof THF dropwise. The reaction was slowly allowed to warm to room temperature and stirred for 3 h. The reaction was cooled back to 0 oC and quenched with 0.5 mL of water, followed by 0.5 mL of 15 % NaOH, and additional 1.5 mL of water and stirred for 30 mins. The reaction mixture was filtered through Celite, filtrate washed with ethyl acetate and concentrtaed under vacuum. The crude residue was purified by silica gel chromatography using 0-40% EtOAc in hexane on a 40 g Agela column to give two fractions. The less polar product is desired(6R,6aR)-2,2-dimethyl-6-vinyl-4,5,6,6a-tetrahydro-3aH-cyclopenta[d][1,3]dioxol-4-ol (830 mg, 4.5052 mmol, 71.386% yield){{2:row 1}}_XXXXX_  [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "10", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "07/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138789", "MODIFIED_DATE": "24/10/2016", "COMPLETED_DATE": "20/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138789", "COUNTERSIGNED_DATE": "24/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146029', 'AetherGen-masks2', 'This compound was sent by Jun Qi from DFCI   Hi, Kris,    Here is the tracking number for the shipment.  777391828604   Let me know if you have any question.   Thanks  jun     Jun Qi, Ph.D.   Assistant Professor of Medicine, Department of Cancer Biology Dana-Farber Cancer Institute Harvard Medical School 360 Longwood Ave. LC-2210 Boston, MA 02115 617-632-6629  617-582-8290 jun_qi@dfci.harvard.edu   [AetherGen LIMS Verified]', '{"BOOK": "9", "ISID": "s.chen2", "PAGE": "2", "DESCR": "EZ53", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138788", "MODIFIED_DATE": "09/11/2016", "COMPLETED_DATE": "01/11/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138788", "COUNTERSIGNED_DATE": "09/11/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146028', 'AetherGen-masks2', 'To 4-Chloropyridine-2,3-diamine (110.0 mg, 0.77 mmol){{9:row 2}}_XXXXX_  in 4 mL of DMF was added the 4-Benzyloxybenzaldehyde (195.14 mg, 0.92 mmol){{9:row 1}}_XXXXX_  and 10 mg of pTsOH. The reaction was heated in a sealed tube at 100 oC for 16 h. The reaction was diluted with water, extracted with ethyl acetate, the EtOAc layer was washed with water, brine, dried over sodium sulfate, filterred and concentrated. The crude triturated with DCM to give a solid that was filtered. The solid was washed with EtOAc, DCM to give 2-(4-benzyloxyphenyl)-7-chloro-3H-imidazo[4,5-b]pyridine (60 mg, 0.17868 mmol, 23.321% yield){{2:row 1}}_XXXXX_ . [AetherGen LIMS Verified]', '{"BOOK": "6", "ISID": "a.pl", "PAGE": "9", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "chemist_052", "EXPERIMENT_ID": "138787", "MODIFIED_DATE": "15/11/2016", "COMPLETED_DATE": "31/10/2016", "COMPLETED_ISID": "a.pl", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138787", "COUNTERSIGNED_DATE": "15/11/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146027', 'AetherGen-masks2', 'A mixture of (2R,3R,4S,5R)-2-(4-amino-5-iodo-pyrrolo[2,3-d]pyrimidin-7-yl)-5-(hydroxymethyl)tetrahydrofuran-3,4-diol (1000.0 mg, 2.55 mmol){{9:row 1}}_XXXXX_ , 2,2-Dimethoxypropane (3.14 mL, 25.5 mmol){{9:row 2}}_XXXXX_ , and 4-methylbenzenesulfonic acid;hydrate (97.01 mg, 0.51 mmol){{9:row 3}}_XXXXX_  in DMF (5 mL){{3:row 1}}_XXXXX_  was heated in a sealed reactor at 80 °C{{8:row 1}}_XXXXX_  overnight. Starting material remained and multiple spots were formed. The reaction was discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "20", "DESCR": "JP-0057", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "06/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138786", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "04/12/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138786", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146026', 'AetherGen-masks2', 'A mixture of [(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (400.0 mg, 0.69 mmol){{9:row 1}}_XXXXX_ , and sodium;iodide (311.8 mg, 2.08 mmol){{9:row 2}}_XXXXX_  in Acetone (5 mL){{3:row 1}}_XXXXX_  was stirred at 60 °C{{8:row 1}}_XXXXX_  overnight. TLC showed no product (should be less polar) but only the polar spot that was likely the hydrolyzed by-product. Discarded. [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "19", "DESCR": "Iodide replacement of Tosylate", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "05/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138785", "MODIFIED_DATE": "20/12/2016", "COMPLETED_DATE": "04/12/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138785", "COUNTERSIGNED_DATE": "20/12/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146025', 'AetherGen-masks2', 'Purchased from Cayman to be tested in PRMT assays Item:13603, batch 0459019-10 http://www.commonchemistry.org/ChemicalDetail.aspx?ref=979-92-0  [AetherGen LIMS Verified]', '{"BOOK": "9", "ISID": "s.chen2", "PAGE": "1", "DESCR": "SAH", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "05/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138784", "MODIFIED_DATE": "31/10/2016", "COMPLETED_DATE": "30/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138784", "COUNTERSIGNED_DATE": "31/10/2016"}', '2025-02-20');
INSERT INTO public.eln_writeup_anonymized (exp_id, system_name, write_up, summary_data, analysis_date) VALUES ('146016', 'AetherGen-masks2', 'A mixture of[(3aR,4R,6R,6aR)-4-(6-aminopurin-9-yl)-2,2-dimethyl-3a,4,6,6a-tetrahydrofuro[3,4-d][1,3]dioxol-6-yl]methyl 4-methylbenzenesulfonate (100.0 mg, 0.17 mmol){{9:row 1}}_XXXXX_ , azetidine-3-carbonitrile hydrochloride (41.11 mg, 0.35 mmol){{9:row 2}}_XXXXX_ , in IPA (1 mL){{3:row 1}}_XXXXX_  was heated at 80 °C{{8:row 1}}_XXXXX_  overnight.   The TLC showed OTs was hydrolyzed back to OH. This reaction can''t use TEA as base as it forms stable ammonium salt. Hunig base would be used for this type of reaction. Discard This target was not pursued further due to azetine analog MD-0041/PRT1000096 was inactive [AetherGen LIMS Verified]', '{"BOOK": "4", "ISID": "s.chen2", "PAGE": "18", "DESCR": "Cyanoazetidine replacement of TsO", "STATUS": "0", "PROTOCOL": "ChemELN", "PROTOCOL_ID": "81", "CREATED_DATE": "03/10/2016", "PDF_COMPLETE": "Y", "COUNTERSIGNER": "biochemist_021", "EXPERIMENT_ID": "138775", "MODIFIED_DATE": "11/10/2016", "COMPLETED_DATE": "11/10/2016", "COMPLETED_ISID": "s.chen2", "CURRENT_VERSION": "1", "EXPERIMENT_NAME": "138775", "COUNTERSIGNED_DATE": "11/10/2016"}', '2025-02-20');
